<?php
require __DIR__ . '/bootstrap.php';
$instanceId = (int) ($_GET['instance_id'] ?? 0); if (!$instanceId) exit('Instância obrigatória.');
$auth->requireInstanceAccess($instanceId); $instance = $auth->instanceById($instanceId); $centers = $financial->centers($instanceId); $categories = $financial->categories($instanceId); $accounts = $financial->accounts($instanceId); $recurring = $financial->recurring($instanceId); $message=$error=null;
if ($_SERVER['REQUEST_METHOD']==='POST' && (($_POST['action']??'')==='create')) { try { $stmt=$pdo->prepare('INSERT INTO financial_recurring (instance_id, description, amount, type, frequency, due_day, start_date, end_date, account_id, center_id, category_id, payment_method, active, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 1, ?, ?)'); $stmt->execute([$instanceId, trim($_POST['description']), (float)$_POST['amount'], $_POST['type'], $_POST['frequency'], $_POST['due_day']?:null, $_POST['start_date'], $_POST['end_date']?:null, (int)$_POST['account_id'], (int)$_POST['center_id'], (int)$_POST['category_id'], $_POST['payment_method'], date('Y-m-d H:i:s'), date('Y-m-d H:i:s')]); $message='Recorrência criada.'; } catch (Throwable $e) { $error=$e->getMessage(); } }
?><!doctype html><html lang="pt-br"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Recorrências</title><link rel="stylesheet" href="<?= e(base_path('assets/ui.css')) ?>"></head><body><div class="wrap"><?php financial_nav($instanceId,'recurring'); ?><div class="card"><h1 class="headline">Recorrências</h1><?php if($message):?><div class="toast good"><?= e($message) ?></div><?php endif; if($error):?><div class="toast bad"><?= e($error) ?></div><?php endif; ?><form method="post" class="split"><input type="hidden" name="action" value="create"><label>Descrição<input name="description"></label><label>Valor<input name="amount" type="number" step="0.01"></label><label>Tipo<select name="type"><option>income</option><option>expense</option><option>transfer</option></select></label><label>Frequência<select name="frequency"><option>weekly</option><option>monthly</option><option>yearly</option></select></label><label>Vencimento<input name="due_day" type="number" min="1" max="31"></label><label>Início<input name="start_date" type="date" value="<?= date('Y-m-d') ?>"></label><label>Fim<input name="end_date" type="date"></label><label>Conta<select name="account_id"><?php foreach($accounts as $a):?><option value="<?= (int)$a['id'] ?>"><?= e($a['name']) ?></option><?php endforeach; ?></select></label><label>Centro<select name="center_id"><?php foreach($centers as $c):?><option value="<?= (int)$c['id'] ?>"><?= e($c['name']) ?></option><?php endforeach; ?></select></label><label>Categoria<select name="category_id"><?php foreach($categories as $c):?><option value="<?= (int)$c['id'] ?>"><?= e($c['name']) ?></option><?php endforeach; ?></select></label><label>Forma<select name="payment_method"><option>pix</option><option>cash</option><option>debit</option><option>credit_card</option><option>boleto</option><option>transfer</option><option>other</option></select></label><button class="btn btn-primary">Criar</button></form></div><div class="card"><div class="list"><?php foreach($recurring as $r): ?><div class="member"><div class="meta"><strong><?= e($r['description']) ?></strong><span class="muted"><?= e($r['frequency']) ?> · <?= e($r['type']) ?></span></div><span class="tag">R$ <?= number_format((float)$r['amount'],2,',','.') ?></span></div><?php endforeach; ?></div></div></div></body></html>
